clc; clear; close all;

%% ---------------------- VEHICLE & ENVIRONMENT ---------------------------
g               = 9.81;           % m/s^2
rho_air         = 1.225;          % kg/m^3
mass_veh        = 1550;           % kg (incl. driver)
A_frontal       = 2.25;           % m^2
Cd              = 0.27;           % -
Cr              = 0.0125;         % rolling resistance coeff
wheel_radius    = 0.315;          % m
gear_ratio      = 9.2;            % single-speed reduction
driveline_eff   = 0.97;           % gearbox/driveshaft efficiency

%% ---------------------------- BATTERY PACK ------------------------------
capacity_kWh    = 62;             % kWh
V_nom           = 360;            % nominal pack voltage (V)
V_min           = 280;            % min allowed pack voltage
V_max           = 420;            % max allowed pack voltage
SOC_init        = 0.90;           % initial SOC (fraction)
SOC_min         = 0.10;           % soft lower bound
SOC_max         = 0.98;           % charge ceiling for regen limiting

% Internal resistance & OCV (simple but realistic-ish)
R0_ohm          = 0.09/100;       % base pack resistance (~0.0009 Ohm)
R_scale_SOC     = [0 0.2 0.5 0.8 1.0]; 
R_mult_SOC      = [1.25 1.15 1.0 0.95 0.95]; % lower at mid-SOC

% Thermal model
T_amb           = 298;            % K (25°C)
T_batt0         = 303;            % K (30°C start)
C_th            = 14e3;           % J/K (lumped)
hA              = 12;             % W/K (cooling path effective UA)
T_derate_start  = 318;            % K (45°C) start derating
T_derate_stop   = 328;            % K (55°C) heavy derate

% Battery current limits (practical clamp) -> approx 3C charge/discharge
Ah_pack  = (capacity_kWh*1000) / V_nom;   % Ah
I_lim_pos = 3 * Ah_pack;    % A (3C discharge)
I_lim_neg = -3 * Ah_pack;   % A (3C charge limit)

%% ------------------------------ MOTOR/INVERTER --------------------------
% Motor map: Efficiency vs torque & speed
torque_vec      = linspace(0, 320, 140);     % Nm
speed_rpm_vec   = linspace(0, 12000, 160);   % rpm
[TG, SR]        = meshgrid(torque_vec, speed_rpm_vec);

Eff_map = 0.93 ...
    - 3.3e-7*(TG-140).^2 ...
    - 1.6e-9*(SR-4500).^2;            % smooth "hump"
Eff_map = max(min(Eff_map, 0.965), 0.70);   % clamp 70–96.5%

inv_eff         = 0.975;                     % inverter eff

% Motor hard limits
T_max_const     = 320;       % Nm
P_mech_max      = 160e3;     % W
rpm_max         = 12000;     % rpm
regen_T_max     = 200;       % Nm

% Interpolant
Eff_F = griddedInterpolant({speed_rpm_vec, torque_vec}, Eff_map, 'linear', 'nearest');

%% ------------------------------ DRIVE CYCLE -----------------------------
% 15 minutes @ 1 Hz
dt       = 1.0;                         
t        = (0:dt:900)';                 
N        = numel(t);

% Base urban waveform + cruise segments
v = 8 + 4*sin(2*pi*t/180) + 3*sin(2*pi*t/75);
v = max(v, 0);                           
v = v + (t>240 & t<360)*4 + (t>600 & t<720)*3;
v = min(v, 28);                          % ~100 km/h cap

% Road grade (±2.5%)
grade = 0.01*sin(2*pi*t/300) + 0.015*sin(2*pi*t/700);
grade = max(min(grade, 0.025), -0.025);

% Aux loads
P_aux = 600 + 200*(t>300 & t<600) + 100*(t>700); % W

%% ---------------------------- ECO FILTERS --------------------------------
% Smooth driver demand
accel_raw       = [0; diff(v)/dt];
accel_filt      = lowpass1(accel_raw, 0.35);
jerk_limit      = 0.8;                         
accel_smooth    = limit_jerk(accel_filt, jerk_limit, dt);

% Look-ahead decel detection (avg dv over next 5 s)
look_ahead_hz   = 5;
dv_next         = [diff(v); 0];
dv_future_avg   = movmean([dv_next; zeros(look_ahead_hz,1)], look_ahead_hz, 'Endpoints','fill');
dv_future_avg   = dv_future_avg(1:N); % keep length N
eco_glide_flag  = dv_future_avg < -0.05;
SOC             = SOC_init;
T_batt          = T_batt0;

soc_series      = zeros(N,1);        soc_series(1) = SOC;
Tbatt_series    = zeros(N,1);        Tbatt_series(1)= T_batt;
P_trac_series   = zeros(N,1);
P_mech_series   = zeros(N,1);
P_elec_series   = zeros(N,1);
P_aux_series    = P_aux(:);
eff_series      = zeros(N,1);
mode_series     = strings(N,1);
I_series        = zeros(N,1);
rpm_series      = zeros(N,1);
T_series        = zeros(N,1);
regen_energy    = 0;

%% ---------------------------- PRECOMPUTE ---------------------------------
% Distance helper (not used later, just for info)
v_mid   = (v + [v(1); v(1:end-1)])/2;
dist_m  = sum(v_mid)*dt;

%% ---------------------------- MAIN SIM LOOP ------------------------------
for k = 2:N
    % Kinematics
    vk   = v(k);
    ak   = accel_smooth(k);
    dtk  = dt;

    % Resistive forces
    F_roll = Cr*mass_veh*g*cos(atan(grade(k)));
    F_drag = 0.5*rho_air*Cd*A_frontal*vk^2;
    F_grade= mass_veh*g*sin(atan(grade(k)));
    F_iner = mass_veh*ak;

    % Tractive force demand
    F_trac = F_roll + F_drag + F_grade + F_iner;

    % Wheel torque & motor speed
    T_wheel   = F_trac*wheel_radius;
    omega_w   = max(vk/wheel_radius, 0);      
    rpm_motor = min(omega_w*gear_ratio * 60/(2*pi), rpm_max);
    rpm_series(k) = rpm_motor;

    % Mode selection
    mode = "DRIVE";
    if (abs(ak) < 0.05 && vk > 2) || eco_glide_flag(k)
        mode = "ECO-GLIDE";
        F_trac = F_roll + 0.2*F_drag + F_grade; 
        T_wheel = F_trac*wheel_radius;
    end
    if T_wheel < 0 && vk > 1
        mode = "REGEN";
    end

    % Apply torque limits
    if mode ~= "REGEN"
        T_wheel = max(0, T_wheel);
    else
        T_wheel = min(0, T_wheel);
    end

    % Wheel->motor torque (incl. gear)
    T_motor = (T_wheel / wheel_radius) / gear_ratio;
    if mode ~= "REGEN"
        T_motor = min(max(T_motor, 0), T_max_const);
    else
        T_motor = -min(abs(T_motor), regen_T_max);
    end
    T_series(k) = T_motor;

    % Mechanical power at shaft
    omega_m = rpm_motor * 2*pi/60;
    P_mech  = T_motor * omega_m;   
    P_mech  = min(max(P_mech, -P_mech_max), P_mech_max);
    P_mech_series(k) = P_mech;

    % Motor+inverter efficiency
    eff = Eff_F(rpm_motor, abs(T_motor));
    eff = max(min(eff, 0.97), 0.70);
    eff_series(k) = eff;

    if P_mech >= 0
        P_elec_motor = P_mech/(eff*inv_eff);   % draw
    else
        P_elec_motor = P_mech*(eff*inv_eff);   % regen (negative)
    end

    % Regen limiting at high SOC / low speed
    if mode == "REGEN"
        regen_scale = 1.0;
        if SOC > 0.9, regen_scale = regen_scale * (1 - (SOC-0.9)/0.08); end
        if vk < 3,   regen_scale = regen_scale * (vk/3);                  end
        regen_scale = max(min(regen_scale,1), 0);
        P_elec_motor = P_elec_motor * regen_scale;
    end
    % Add auxiliaries
    P_dc = P_elec_motor + P_aux(k);   % +ve draw, -ve charge

    % Battery OCV & Resistance
    Voc  = OCV_from_SOC(SOC, V_min, V_max);   
    Rint = R_from_SOC_T(SOC, T_batt, R0_ohm, R_scale_SOC, R_mult_SOC);

    % Temp derating (draw side only)
    derate = 1.0;
    if T_batt >= T_derate_start && T_batt < T_derate_stop
        derate = max(0.3, 1 - (T_batt - T_derate_start)/(T_derate_stop - T_derate_start));
    elseif T_batt >= T_derate_stop
        derate = 0.25;
    end
    if P_dc > 0
        P_dc = P_dc * derate;
    end

    % SOC-based draw cap & stronger regen when low SOC
    if SOC < 0.18 && P_dc > 0
        P_dc = P_dc * 0.8;
    elseif SOC < 0.12 && P_dc > 0
        P_dc = P_dc * 0.6;
    end
    if SOC < 0.15 && mode == "REGEN"
        P_dc = P_dc * 1.15;
    end

    %% --- Robust solve for I from P = Voc*I - Rint*I^2 ---
    % Quadratic: a*I^2 + b*I + c = 0 with a = Rint, b = -Voc, c = P_dc
    a = Rint; b = -Voc; c = P_dc;
    disc = b^2 - 4*a*c;
    if disc < 0
        % Numerical: clamp P_dc to feasible max/min
        P_max_feasible = (Voc^2)/(4*a);
        if P_dc > P_max_feasible
            P_dc = P_max_feasible;
        elseif P_dc < -P_max_feasible
            P_dc = -P_max_feasible;
        end
        disc = b^2 - 4*a*c;
    end

    I1 = (-b + sqrt(max(disc,0)))/(2*a);
    I2 = (-b - sqrt(max(disc,0)))/(2*a);

    % Choose physically meaningful root:
    % - If P_dc >= 0 (discharge), choose the positive root that is smaller (near real operating current)
    % - If P_dc < 0 (charging), choose the negative root (charging current negative)
    if P_dc >= 0
        % pick the root that is positive and <= Voc/(2*Rint) (the smaller of the two positive roots)
        candidates = sort([I1, I2]);
        % choose the smaller positive root
        if candidates(1) >= 0
            I = candidates(1);
        elseif candidates(2) >= 0
            I = candidates(2);
        else
            % fallback
            I = max(candidates);
        end
    else
        % P_dc < 0 -> expect negative I (charging)
        if I1 < 0 && I2 < 0
            I = max(I1, I2); % the one closer to zero (less negative)
        elseif I1 < 0
            I = I1;
        elseif I2 < 0
            I = I2;
        else
            % if both positive due to numerical issues, pick small negative clamp
            I = -min(abs(I1), abs(I2));
        end
    end

    % Clamp currents to realistic C-rate limits and re-evaluate P_dc accordingly
    I_prev = I;
    I = min(max(I, I_lim_neg), I_lim_pos);

    % Recompute P_dc to be consistent with chosen/clamped I: P = Voc*I - R*I^2
    P_dc = Voc * I - Rint * I^2;
    % auxiliaries already included earlier via P_elec_motor + P_aux

    %% Update SOC via Coulomb counting (Ah -> A*s)
    % Ah_pack is in Ah; 1 Ah = 3600 A*s
    dSOC = -(I * dtk) / (Ah_pack * 3600);
    SOC  = min(max(SOC + dSOC, 0), 1);

    %% Battery thermal update
    Qgen   = (I^2)*Rint;                 % W
    Qcool  = hA*(T_batt - T_amb);        % W
    T_batt = T_batt + (Qgen - Qcool)*dtk / C_th;

    %% Regen energy tally (J)
    if P_dc < 0
        regen_energy = regen_energy + (-P_dc)*dtk;
    end
    %% Logging
    P_elec_series(k) = P_dc;
    soc_series(k)    = SOC;
    Tbatt_series(k)  = T_batt;
    mode_series(k)   = mode;
    I_series(k)      = I;
    P_trac_series(k) = F_trac*vk;
end

%% ------------------------------ KPIs ------------------------------------
dist_km     = sum((v(1:end-1)+v(2:end))/2)*dt / 1000;           
energy_Wh   = trapz((P_elec_series.*(P_elec_series>0)))*dt/3600; 
energy_Wh_km= energy_Wh / max(dist_km, 1e-9);
regen_kWh   = regen_energy/3.6e6;

fprintf('\n============= EV Energy Management Results =============\n'); %[output:54a02075]
fprintf('Distance driven        : %.2f km\n', dist_km); %[output:5817640d]
fprintf('Net energy used (draw) : %.2f kWh\n', energy_Wh/1000); %[output:0f39004e]
fprintf('Consumption            : %.1f Wh/km\n', energy_Wh_km); %[output:569bf9e7]
fprintf('Regenerated energy     : %.2f kWh\n', regen_kWh); %[output:0e7aff14]
fprintf('Final SOC              : %.1f %%n', soc_series(end)*100); %[output:2a1ee3f1]
fprintf('Max battery temp       : %.1f °C\n', max(Tbatt_series-273.15)); %[output:84649839]
fprintf('========================================================\n\n'); %[output:97bbac06]

%% ------------------------------ PLOTS -----------------------------------
figure('Name','EV Energy-Efficient EMS','Color','w','Position',[80 80 1100 900]); %[output:6b211828]
tmin = (t - t(1))/60;

subplot(4,1,1); %[output:6b211828]
plot(tmin, v, 'LineWidth',1.5); grid on; %[output:6b211828]
ylabel('Speed (m/s)'); title('Drive Cycle & Grade'); %[output:6b211828]
yyaxis right; plot(tmin, grade*100, '--', 'LineWidth',1.0); %[output:6b211828]
ylabel('Grade (%)'); %[output:6b211828]

subplot(4,1,2); %[output:6b211828]
plot(tmin, P_trac_series/1000, 'LineWidth',1.2); hold on; grid on; %[output:6b211828]
plot(tmin, P_elec_series/1000, 'LineWidth',1.2); %[output:6b211828]
plot(tmin, P_aux_series/1000, 'LineWidth',1.0); %[output:6b211828]
ylabel('Power (kW)'); %[output:6b211828]
legend('Road Tractive (approx)','Battery DC (+draw/-regen)','Aux','Location','best'); %[output:6b211828]
title('Power Flows'); %[output:6b211828]

subplot(4,1,3); %[output:6b211828]
plot(tmin, soc_series*100, 'LineWidth',1.6); grid on; hold on; %[output:6b211828]
yline(SOC_min*100,':'); yline(SOC_max*100,':'); %[output:6b211828]
ylabel('SOC (%)'); title('State of Charge'); %[output:6b211828]

subplot(4,1,4); %[output:6b211828]
plot(tmin, Tbatt_series-273.15, 'LineWidth',1.6); grid on; hold on; %[output:6b211828]
yline(T_derate_start-273.15,':'); yline(T_derate_stop-273.15,':'); %[output:6b211828]
ylabel('T_{batt} (°C)'); xlabel('Time (min)'); title('Battery Temperature & Derate Bands'); %[output:6b211828]

subplot(4,1,4) %[output:6b211828]
xlim([0.00 15.00]) %[output:6b211828]
ylim([27.2 60.0]) %[output:6b211828]

% Mode timeline using stairs for clarity
figure('Name','Mode Timeline','Color','w','Position',[120 120 1100 180]); %[output:2a1a5dcd]
modes_num = zeros(N,1);
modes_num(mode_series=="DRIVE")     = 1;
modes_num(mode_series=="ECO-GLIDE") = 2;
modes_num(mode_series=="REGEN")     = 3;
stairs(tmin, modes_num, 'LineWidth', 2); ylim([0 4]); yticks([1 2 3]); %[output:2a1a5dcd]
yticklabels({'DRIVE','ECO-GLIDE','REGEN'}); %[output:2a1a5dcd]
xlabel('Time (min)'); title('Mode Timeline'); grid on; %[output:2a1a5dcd]

%% --------------------------- HELPER FUNCS -------------------------------
function y = lowpass1(x, alpha)
% First-order IIR low-pass: y(k)=y(k-1)+alpha*(x(k)-y(k-1))
alpha = max(min(alpha,0.99), 0.01);
y = zeros(size(x));
y(1) = x(1);
for i=2:numel(x)
    y(i) = y(i-1) + alpha*(x(i)-y(i-1));
end
end

function a = limit_jerk(a_in, jmax, dt)
% Limit jerk by clamping successive accel increments
a = a_in;
for i=2:numel(a)
    da = a(i) - a(i-1);
    da = max(min(da, jmax*dt), -jmax*dt);
    a(i) = a(i-1) + da;
end
end
function Voc = OCV_from_SOC(soc, Vmin, Vmax)
% Simple piecewise-ish OCV curve
soc = max(min(soc,1),0);
Voc = Vmin + (Vmax - Vmin) * (0.05 + 0.90 * (1 - exp(-4*soc)) / (1 - exp(-4)));
Voc = max(min(Voc, Vmax), Vmin);
end

function Rint = R_from_SOC_T(soc, T, R0, soc_knots, soc_mult)
% SOC & temperature scaling of internal resistance
soc = max(min(soc,1),0);
mult_soc = interp1(soc_knots, soc_mult, soc, 'linear', 'extrap');
T_C = T - 273.15;
mult_T = 1.0;
if T_C < 10,  mult_T = 1.15; end
if T_C < 0,   mult_T = 1.30; end
if T_C > 40,  mult_T = 1.15; end
if T_C > 50,  mult_T = 1.35; end
Rint = max(R0 * mult_soc * mult_T, 1e-5);
end

